import React from "react";
import StatsCard from "./components/StatsCard";
import { useLayout } from "@/framework/layouts/LayoutProvider";

export default function Dashboard() {
  const { setLayout } = useLayout();

  React.useEffect(() => {
    setLayout("default");
  }, [setLayout]);

  return (
    <div style={{ padding: 24 }}>
      <h1>Sample Platform — Dashboard</h1>
      <p>
        This is a sample platform page. Platform-specific pages live under{" "}
        <code>src/platforms/</code>.
      </p>

      <section style={{ marginTop: 16 }}>
        <h2>Overview</h2>
        <div style={{ display: "flex", gap: 12 }}>
          <StatsCard title="Users" value="1,234" />
          <StatsCard title="Active" value="98%" />
        </div>
      </section>
    </div>
  );
}
